/**
 * LGPD/GDPR User Data Export Engine
 *
 * Pure functions for collecting, formatting, and packaging user data
 * for compliance with data portability requirements.
 *
 * References:
 * - LGPD Art. 18, V (Lei 13.709/2018) — Portabilidade de dados
 * - GDPR Art. 20 — Right to data portability
 */

// ─── Types ────────────────────────────────────────────────────────────────────

export interface UserDataExport {
  exportId: string;
  exportDate: string;
  userId: string;
  format: 'json';
  version: '1.0';
  data: {
    profile: UserProfileData;
    projects: ProjectData[];
    videos: VideoData[];
    settings: UserSettingsData;
    activity: ActivityRecord[];
    billing: BillingData | null;
    storage: StorageUsageData;
  };
  metadata: ExportMetadata;
}

export interface UserProfileData {
  id: string;
  email: string;
  name: string | null;
  avatarUrl: string | null;
  createdAt: string;
  lastSignIn: string | null;
  provider: string;
  emailVerified: boolean;
}

export interface ProjectData {
  id: string;
  title: string;
  description: string | null;
  status: string;
  slideCount: number;
  duration: number | null;
  createdAt: string;
  updatedAt: string;
  scenes: SceneSummary[];
}

export interface SceneSummary {
  id: string;
  order: number;
  duration: number;
  hasAudio: boolean;
  hasAvatar: boolean;
  scriptLength: number;
}

export interface VideoData {
  id: string;
  projectId: string;
  title: string;
  status: string;
  resolution: string | null;
  duration: number | null;
  fileSize: number | null;
  format: string | null;
  createdAt: string;
  downloadUrl: string | null;
}

export interface UserSettingsData {
  theme: string;
  language: string;
  notifications: boolean;
  defaultVoice: string | null;
  defaultResolution: string | null;
  onboardingCompleted: boolean;
}

export interface ActivityRecord {
  type: string;
  timestamp: string;
  details: string | null;
}

export interface BillingData {
  plan: string;
  status: string;
  currentPeriodStart: string | null;
  currentPeriodEnd: string | null;
  cancelAtPeriodEnd: boolean;
}

export interface StorageUsageData {
  totalBytes: number;
  totalFiles: number;
  breakdown: {
    videos: number;
    images: number;
    audio: number;
    other: number;
  };
}

export interface ExportMetadata {
  generatedAt: string;
  generatedBy: string;
  requestedAt: string;
  processingTimeMs: number;
  totalRecords: number;
  dataCategories: string[];
  legalBasis: string;
  retentionPolicy: string;
}

export type ExportStatus = 'pending' | 'processing' | 'completed' | 'failed' | 'expired';

export interface ExportRequest {
  id: string;
  userId: string;
  status: ExportStatus;
  requestedAt: string;
  completedAt: string | null;
  downloadUrl: string | null;
  expiresAt: string | null;
  errorMessage: string | null;
  fileSize: number | null;
}

// ─── Constants ────────────────────────────────────────────────────────────────

export const EXPORT_EXPIRY_HOURS = 48;
export const MAX_EXPORT_SIZE_MB = 500;
export const EXPORT_COOLDOWN_HOURS = 24;

export const DATA_CATEGORIES = [
  'profile',
  'projects',
  'videos',
  'settings',
  'activity',
  'billing',
  'storage',
] as const;

export const LGPD_LEGAL_BASIS =
  'Art. 18, V - LGPD (Lei 13.709/2018) - Portabilidade de dados';
export const GDPR_LEGAL_BASIS =
  'Art. 20 GDPR - Right to data portability';
export const RETENTION_POLICY =
  'Dados retidos enquanto a conta estiver ativa. Export disponível por 48h após geração.';

// ─── Functions ────────────────────────────────────────────────────────────────

/**
 * Build metadata for a data export.
 */
export function buildExportMetadata(
  requestedAt: string,
  processingTimeMs: number,
  totalRecords: number,
): ExportMetadata {
  return {
    generatedAt: new Date().toISOString(),
    generatedBy: 'system',
    requestedAt,
    processingTimeMs,
    totalRecords,
    dataCategories: [...DATA_CATEGORIES],
    legalBasis: `${LGPD_LEGAL_BASIS} / ${GDPR_LEGAL_BASIS}`,
    retentionPolicy: RETENTION_POLICY,
  };
}

/**
 * Validate whether a user can request a new export (24h cooldown).
 */
export function validateExportRequest(
  userId: string,
  lastExportAt: string | null,
): { valid: boolean; reason?: string } {
  if (!userId || userId.trim().length === 0) {
    return { valid: false, reason: 'userId é obrigatório' };
  }

  if (lastExportAt === null) {
    return { valid: true };
  }

  const lastExport = new Date(lastExportAt).getTime();
  const now = Date.now();
  const cooldownMs = EXPORT_COOLDOWN_HOURS * 60 * 60 * 1000;

  if (now - lastExport < cooldownMs) {
    const remainingMs = cooldownMs - (now - lastExport);
    const remainingHours = Math.ceil(remainingMs / (60 * 60 * 1000));
    return {
      valid: false,
      reason: `Aguarde ${remainingHours}h antes de solicitar outro export. Último export: ${lastExportAt}`,
    };
  }

  return { valid: true };
}

/**
 * Assemble the full user data export object.
 */
export function buildUserDataExport(params: {
  userId: string;
  exportId: string;
  profile: UserProfileData;
  projects: ProjectData[];
  videos: VideoData[];
  settings: UserSettingsData;
  activity: ActivityRecord[];
  billing: BillingData | null;
  storage: StorageUsageData;
  requestedAt: string;
  processingTimeMs: number;
}): UserDataExport {
  const totalRecords = countTotalRecords({
    profile: params.profile,
    projects: params.projects,
    videos: params.videos,
    settings: params.settings,
    activity: params.activity,
    billing: params.billing,
    storage: params.storage,
  });

  const metadata = buildExportMetadata(
    params.requestedAt,
    params.processingTimeMs,
    totalRecords,
  );

  return {
    exportId: params.exportId,
    exportDate: new Date().toISOString(),
    userId: params.userId,
    format: 'json',
    version: '1.0',
    data: {
      profile: params.profile,
      projects: params.projects,
      videos: params.videos,
      settings: params.settings,
      activity: params.activity,
      billing: params.billing,
      storage: params.storage,
    },
    metadata,
  };
}

/**
 * Estimate the JSON export size in bytes.
 */
export function calculateExportSize(exportData: UserDataExport): number {
  const json = JSON.stringify(exportData);
  return new TextEncoder().encode(json).byteLength;
}

/**
 * Generate the standard export filename.
 * Returns: 'user-data-export-{userId}-{YYYY-MM-DD}.json'
 */
export function formatExportFilename(userId: string, date: string): string {
  const dateStr = date.substring(0, 10); // YYYY-MM-DD from ISO string
  return `user-data-export-${userId}-${dateStr}.json`;
}

/**
 * Compute expiry date (48h after completion).
 */
export function getExportExpiryDate(completedAt: string): string {
  const completed = new Date(completedAt);
  completed.setHours(completed.getHours() + EXPORT_EXPIRY_HOURS);
  return completed.toISOString();
}

/**
 * Check whether an export download link has expired.
 */
export function isExportExpired(expiresAt: string): boolean {
  return new Date(expiresAt).getTime() <= Date.now();
}

/**
 * Count total records across all data categories.
 */
export function countTotalRecords(data: UserDataExport['data']): number {
  let count = 0;
  count += 1; // profile
  count += data.projects.length;
  count += data.videos.length;
  count += 1; // settings
  count += data.activity.length;
  if (data.billing !== null) {
    count += 1;
  }
  count += 1; // storage
  return count;
}

/**
 * Generate a human-friendly summary of an export.
 */
export function summarizeExport(exportData: UserDataExport): {
  categories: string[];
  totalRecords: number;
  estimatedSizeKB: number;
  projectCount: number;
  videoCount: number;
} {
  const sizeBytes = calculateExportSize(exportData);
  return {
    categories: [...DATA_CATEGORIES],
    totalRecords: exportData.metadata.totalRecords,
    estimatedSizeKB: Math.ceil(sizeBytes / 1024),
    projectCount: exportData.data.projects.length,
    videoCount: exportData.data.videos.length,
  };
}

/**
 * Redact sensitive fields for logging purposes (NOT for the actual export).
 * Partially hides the email: j***@example.com
 */
export function redactSensitiveFields(profile: UserProfileData): UserProfileData {
  const email = profile.email;
  let redactedEmail = email;

  if (email && email.includes('@')) {
    const [local, domain] = email.split('@');
    if (local.length > 1) {
      redactedEmail = `${local[0]}${'*'.repeat(Math.min(local.length - 1, 3))}@${domain}`;
    } else {
      redactedEmail = `*@${domain}`;
    }
  }

  return {
    ...profile,
    email: redactedEmail,
  };
}

/**
 * Build a single activity record with current timestamp.
 */
export function buildActivityRecord(
  type: string,
  details?: string,
): ActivityRecord {
  return {
    type,
    timestamp: new Date().toISOString(),
    details: details ?? null,
  };
}
